"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[78807],{16813:e=>{e.exports=JSON.parse('{"tag":{"label":"malocclusion","permalink":"/docs/tags/malocclusion","allTagsPath":"/docs/tags","count":13,"items":[{"id":"Mice/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Mice","description":"An overview of the most common health issues affecting pet mice, with a focus on the pervasive nature of respiratory disease (Mycoplasma), their high rate of tumors, and common parasites.","permalink":"/docs/Mice/illnesses-and-conditions/common-health-issues"},{"id":"Rats/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Rats","description":"An overview of the most common health issues affecting pet rats, focusing on the chronic nature of Mycoplasma respiratory infections, the high incidence of mammary tumors, and conditions like bumblefoot.","permalink":"/docs/Rats/illnesses-and-conditions/common-health-issues"},{"id":"Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas","title":"Dental Disease in Chinchillas","description":"Learn about the causes, symptoms, and treatment of dental disease and malocclusion in chinchillas, including how diet and genetics play a role.","permalink":"/docs/Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas"},{"id":"guinea-pigs/health-and-wellness/dental-disease","title":"Dental Disease in Guinea Pigs","description":"Dental disease is one of the most common and serious health problems affecting guinea pigs. Unlike humans, a guinea pig\'s teeth grow continuously throughout their life. This continuous growth can...","permalink":"/docs/guinea-pigs/health-and-wellness/dental-disease"},{"id":"Chinchillas/health-and-wellness/dental-health","title":"Dental Health in Chinchillas","description":"A detailed guide to dental disease in chinchillas, covering the causes of malocclusion, recognizing the signs of dental problems, and the critical role of a high-hay diet in prevention.","permalink":"/docs/Chinchillas/health-and-wellness/dental-health"},{"id":"Degus/health-and-wellness/dental-health","title":"Dental Health in Degus","description":"A comprehensive guide to dental disease in degus, explaining the causes of malocclusion, how to recognize the signs, and the critical importance of a proper, hay-based diet for prevention.","permalink":"/docs/Degus/health-and-wellness/dental-health"},{"id":"Gerbils/health-and-wellness/dental-health","title":"Dental Health in Gerbils","description":"A guide to dental health in gerbils, focusing on the causes and prevention of incisor overgrowth (malocclusion) and the critical role of chewing materials.","permalink":"/docs/Gerbils/health-and-wellness/dental-health"},{"id":"guinea-pigs/health-and-wellness/dental-health","title":"Dental Health in Guinea Pigs","description":"A detailed guide to dental disease in guinea pigs, explaining the causes of malocclusion, how to recognize the signs, and the critical role of a high-hay diet in prevention.","permalink":"/docs/guinea-pigs/health-and-wellness/dental-health"},{"id":"Hamsters/health-and-wellness/dental-health","title":"Dental Health in Hamsters","description":"A guide to dental health in hamsters, focusing on the causes and prevention of incisor overgrowth (malocclusion) and the importance of providing appropriate chew toys.","permalink":"/docs/Hamsters/health-and-wellness/dental-health"},{"id":"Mice/health-and-wellness/dental-health","title":"Dental Health in Mice","description":"A guide to dental health in mice, focusing on the causes and prevention of incisor overgrowth (malocclusion) and the importance of providing a proper diet and chew toys.","permalink":"/docs/Mice/health-and-wellness/dental-health"},{"id":"Rabbits/health-and-wellness/dental-health","title":"Dental Health in Rabbits","description":"An in-depth guide to dental disease in rabbits, explaining why it is so common, how to recognize the signs of oral pain, and the absolute necessity of a hay-based diet for prevention.","permalink":"/docs/Rabbits/health-and-wellness/dental-health"},{"id":"Rats/health-and-wellness/dental-health","title":"Dental Health in Rats","description":"A guide to dental health in rats, focusing on the causes and prevention of incisor overgrowth (malocclusion) and the importance of providing a proper diet and chew toys.","permalink":"/docs/Rats/health-and-wellness/dental-health"},{"id":"Rats/health-and-wellness/rat-dental-care","title":"Rat Dental Care Guide","description":"Dental health is one of the most important \u2014 and most overlooked \u2014 aspects of rat care. Because rat incisors grow continuously throughout life, they must wear down properly to prevent serious complications. A rat with dental problems will struggle to eat, lose weight rapidly, and can deteriorate quickly. Understanding how rat teeth work and how to support healthy dental wear is essential for every rat owner.","permalink":"/docs/Rats/health-and-wellness/rat-dental-care"}],"unlisted":false}}')}}]);